function validateType(type: WireType, value: unknown): boolean {
  switch (type.kind) {
    case "boolean":
      return typeof value === "boolean";
    case "number":
      return validateNumber(type, value);
    case "string":
      return validateString(type, value);
    case "timestamp":
      return typeof value === "string" && isWireRfc3339(value);
    case "json":
      return value !== undefined;
    case "literal":
      return value === type.value;
    case "reference":
      return validate(type.name, value);
    case "array":
      return (
        Array.isArray(value) &&
        (type.maxItems === undefined || value.length <= type.maxItems) &&
        value.every((item) => validateType(type.items, item))
      );
    case "map":
      return (
        isRecord(value) &&
        Object.keys(value).length <= type.maxEntries &&
        Object.entries(value).every(
          ([key, item]) =>
            key.length <= type.keyMaxLength && validateType(type.values, item),
        )
      );
    case "nullable":
      return value === null || validateType(type.value, value);
  }
}

function validate(name: string, value: unknown): boolean {
  const schema = schemas[name];
  if (schema === undefined) return false;
  if (schema.kind === "alias") return validateType(schema.type, value);
  if (schema.kind === "enum") {
    return (
      typeof value === "string" &&
      (schema.unknownPolicy === "preserve" || schema.known.includes(value))
    );
  }
  if (schema.kind === "tagged-union") {
    if (!isRecord(value) || typeof value[schema.discriminator] !== "string")
      return false;
    const variant = schema.variants.find(
      (item) => item.tag === value[schema.discriminator],
    );
    return variant === undefined
      ? schema.unknownPolicy === "preserve"
      : validateType(variant.type, value);
  }
  if (!isRecord(value)) return false;
  const known = new Set(schema.fields.map((field) => field.name));
  for (const field of schema.fields) {
    const fieldValue = value[field.name];
    if (fieldValue === undefined) {
      if (field.required) return false;
      continue;
    }
    if (!validateType(field.type, fieldValue)) return false;
  }
  return (
    schema.unknownFields === "accept" ||
    Object.keys(value).every(
      (key) => known.has(key) || value[key] === undefined,
    )
  );
}

